Salut! Dans le monde de la programmation C++, si tu veux créer un nouveau processus avec un seul file descriptor connecté à son entrée et à sa sortie, tu peux utiliser la fonction `fork()` pour créer le processus fils, puis `dup2()` pour rediriger les file descriptors. Voici un exemple :

```cpp
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <iostream>

int main() {
    int pipefd[2];
    pid_t pid;

    // Créer un pipe
    if (pipe(pipefd) == -1) {
        std::cerr << "Erreur de création du pipe" << std::endl;
        return 1;
    }

    // Fork pour créer un processus fils
    pid = fork();
    if (pid == -1) {
        std::cerr << "Erreur de fork" << std::endl;
        return 1;
    }

    if (pid == 0) { // Code du processus fils
        // Fermer le file descriptor d'écriture du pipe
        close(pipefd[1]);

        // Rediriger l'entrée et la sortie du processus fils vers le pipe
        dup2(pipefd[0], 0); // Entrée (stdin) du processus fils
        dup2(pipefd[0], 1); // Sortie (stdout) du processus fils

        // Fermer le file descriptor supplémentaire
        close(pipefd[0]);

        // Exemple d'exécution d'une commande
        execlp("ls", "ls", NULL);
        std::cerr << "Erreur d'exécution de la commande" << std::endl;
        _exit(1);
    } else { // Code du processus père
        // Fermer le file descriptor de lecture du pipe
        close(pipefd[0]);

        // En attendre le terminaison
        wait(NULL);

        // Fermer le file descriptor de lecture du pipe
        close(pipefd[1]);
    }

    return 0;
}
```

Cet exemple crée un nouveau processus qui redirige son entrée et sa sortie vers un pipe, et exécute la commande `ls`. Bon coding!
